INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (62, 190805, 3.414, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1000001, 0.0, 1, "2025/01/31 12:00:00", -416.5, 2, "カリン", "2030/01/01 14:59:59", 1, 1);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (62, 190805, 3.099, "ミッションをクリアして、\n報酬をゲットしましょう！", 1000002, 0.0, 1, "2025/01/31 12:00:00", -416.5, 2, "カリン", "2030/01/01 14:59:59", 1, 2);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (63, 190805, 2.801, "受け取ることができる\n報酬があるようです\n確認してみてください", 1000003, 0.0, 1, "2025/01/31 12:00:00", -416.5, 2, "カリン", "2030/01/01 14:59:59", 1, 3);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (63, 190805, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 1000004, 0.0, 2, "2025/01/31 12:00:00", -416.5, 2, "カリン", "2030/01/01 14:59:59", 1, 4);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (64, 190805, 2.12, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1000005, 0.0, 2, "2025/01/31 12:00:00", -363.0, 1, "カリン", "2030/01/01 14:59:59", 1, 5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (64, 190805, 1.68, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1000006, 0.0, 1, "2025/01/31 12:00:00", -363.0, 2, "カリン", "2030/01/01 14:59:59", 1, 6);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (64, 190805, 2.33, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1000007, 0.0, 2, "2025/01/31 12:00:00", -363.0, 1, "カリン", "2030/01/01 14:59:59", 1, 7);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 133701, 5.18, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 1020101, -6.0, 3, "2025/01/31 12:00:00", -285.0, 7, "ラビリスタ", "2030/01/01 14:59:59", 10201, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 133901, 8.77, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 1020102, -2.0, 1, "2025/01/31 12:00:00", -285.0, 2, "クリスティーナ", "2030/01/01 14:59:59", 10201, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 133801, 15.5, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 1020103, 0.0, 6, "2025/01/31 12:00:00", -285.0, 1, "ネネカ", "2030/01/01 14:59:59", 10201, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 134301, 9.061, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 1020201, 0.0, 2, "2025/02/28 12:00:00", -285.0, 5, "ランファ", "2030/01/01 14:59:59", 10202, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 134401, 7.699, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 1020202, 0.0, 1, "2025/02/28 12:00:00", -285.0, 2, "チカ", "2030/01/01 14:59:59", 10202, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 134601, 8.595, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 1020301, 0.0, 1, "2025/03/31 12:00:00", -285.0, 2, "アオイ", "2030/01/01 14:59:59", 10203, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 134501, 7.758, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 1020302, 0.0, 1, "2025/03/31 12:00:00", -285.0, 2, "クローチェ", "2030/01/01 14:59:59", 10203, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 132302, 7.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 1020401, 0.0, 2, "2025/04/30 12:00:00", -285.0, 6, "ルイズマリー", "2030/01/01 14:59:59", 10204, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 132402, 7.904, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 1020402, 0.0, 1, "2025/04/30 12:00:00", -285.0, 2, "イロハ", "2030/01/01 14:59:59", 10204, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 132502, 8.487, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 1020403, 0.0, 4, "2025/04/30 12:00:00", -285.0, 2, "ソノ", "2030/01/01 14:59:59", 10204, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 134901, 8.763, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 1020502, 0.0, 1, "2025/05/31 12:00:00", -285.0, 2, "カノン", "2030/01/01 14:59:59", 10205, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 134801, 6.417, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 1020503, 0.0, 1, "2025/05/31 12:00:00", -285.0, 3, "ツムギ", "2030/01/01 14:59:59", 10205, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 135001, 10.335, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 1020601, 0.0, 3, "2025/06/30 12:00:00", -285.0, 7, "エリス", "2030/01/01 14:59:59", 10206, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 135101, 6.281, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 1020602, 0.0, 2, "2025/06/30 12:00:00", -285.0, 4, "シェフィ", "2030/01/01 14:59:59", 10206, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 135201, 12.244, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 1020603, 0.0, 1, "2025/06/30 12:00:00", -285.0, 2, "プレシア", "2030/01/01 14:59:59", 10206, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 135301, 6.339, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 1020701, 0.0, 2, "2025/07/31 12:00:00", -285.0, 8, "クリア", "2030/01/01 14:59:59", 10207, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 135401, 8.184, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 1020702, 0.0, 7, "2025/07/31 12:00:00", -285.0, 9, "アネモネ", "2030/01/01 14:59:59", 10207, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 129101, 3.906, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 1020801, 0.0, 9, "2025/08/31 12:00:00", -285.0, 2, "アイラ", "2030/01/01 14:59:59", 10208, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 129201, 14.465, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 1020802, 0.0, 1, "2025/08/31 12:00:00", -285.0, 2, "シナツ", "2030/01/01 14:59:59", 10208, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 100101, 8.662, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 1020803, 0.0, 4, "2025/08/31 12:00:00", -285.0, 3, "ヒヨリ", "2030/01/01 14:59:59", 10208, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 100301, 10.915, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 1020804, 0.0, 1, "2025/08/31 12:00:00", -285.0, 3, "レイ", "2030/01/01 14:59:59", 10208, 401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 135802, 6.042, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 1020901, 0.0, 1, "2025/09/30 12:00:00", -285.0, 7, "ユキノ", "2030/01/01 14:59:59", 10209, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 135903, 9.402, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 1020902, 0.0, 4, "2025/09/30 12:00:00", -285.0, 1, "サツキ", "2030/01/01 14:59:59", 10209, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 136902, 8.16, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 1020903, 0.0, 8, "2025/09/30 12:00:00", -285.0, 1, "ルルィ", "2030/01/01 14:59:59", 10209, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 137401, 5.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 1021001, 0.0, 3, "2025/10/31 12:00:00", -285.0, 2, "カスミ", "2030/01/01 14:59:59", 10210, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 136001, 8.12, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 1021002, 0.0, 4, "2025/10/31 12:00:00", -285.0, 1, "アラクネ", "2030/01/01 14:59:59", 10210, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 136202, 6.386, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 1021003, 0.0, 4, "2025/10/31 12:00:00", -285.0, 2, "ナーナ", "2030/01/01 14:59:59", 10210, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 136402, 7.438, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 1021101, 0.0, 3, "2025/11/30 12:00:00", -285.0, 4, "ユイ", "2030/01/01 14:59:59", 10211, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 136302, 8.35, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 1021102, 0.0, 1, "2025/11/30 12:00:00", -285.0, 5, "ミソラ", "2030/01/01 14:59:59", 10211, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 136501, 5.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 1021201, 0.0, 1, "2025/12/31 12:00:00", -285.0, 2, "シズル", "2030/01/01 14:59:59", 10212, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 137902, 5.25, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 1021202, 0.0, 1, "2025/12/31 12:00:00", -285.0, 2, "リノ", "2030/01/01 14:59:59", 10212, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 106801, 7.5, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 1021203, 0.0, 1, "2025/12/31 12:00:00", -285.0, 2, "ラビリスタ", "2030/01/01 14:59:59", 10212, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 126501, 8.204, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 1021301, 0.0, 1, "2026/01/31 12:00:00", -285.0, 2, "ライラエル", "2030/01/01 14:59:59", 10213, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 129701, 7.176, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 1021302, 0.0, 1, "2026/01/31 12:00:00", -285.0, 2, "ネフィ＝ネラ", "2030/01/01 14:59:59", 10213, 201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 133101, 8.602, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 1021303, 0.0, 1, "2026/01/31 12:00:00", -285.0, 5, "ヴァイオレット", "2030/01/01 14:59:59", 10213, 301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 138101, 10.14, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 1021304, 0.0, 1, "2026/02/06 12:00:00", -285.0, 3, "ライラエル", "2030/01/01 14:59:59", 10213, 102);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 138201, 10.152, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 1021305, 0.0, 1, "2026/02/06 12:00:00", -285.0, 7, "ネフィ＝ネラ", "2030/01/01 14:59:59", 10213, 202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 138001, 9.688, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 1021306, 0.0, 4, "2026/02/06 12:00:00", -285.0, 3, "ヴァイオレット", "2030/01/01 14:59:59", 10213, 302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 138301, 5.928, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 1021307, 0.0, 2, "2026/02/12 12:00:00", -285.0, 1, "ペコリーヌ", "2030/01/01 14:59:59", 10213, 401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 138702, 9.19, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 1021401, 0.0, 4, "2026/02/28 12:00:00", -285.0, 2, "ワカナ", "2030/01/01 14:59:59", 10214, 101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 138802, 8.724, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 1021402, 0.0, 1, "2026/02/28 12:00:00", -285.0, 3, "シオリ", "2030/01/01 14:59:59", 10214, 201);
